import { db } from "@/app/lib/db";
import { redirect } from "next/navigation";
import { 
  ArrowLeft, Monitor, Cpu, HardDrive, 
  User, Tag, Keyboard, MessageSquare, AlertCircle, 
  Activity, Shield, Calendar, MapPin
} from "lucide-react";
import Link from "next/link";

export default async function PaginaReporteEstatico({ 
  searchParams 
}: { 
  searchParams: Promise<{ id?: string }> 
}) {
  const { id } = await searchParams;


  const result = await db.query('SELECT * FROM computadoras WHERE id = $1', [id]);
  const data = result.rows[0];

  if (!data) return redirect("/vew");

  // Componente de Fila de Datos (Solo Texto)
  const InfoRow = ({ icon: Icon, label, value, highlight = false }: any) => (
    <div className="flex flex-col border-b border-slate-50 py-3 last:border-0">
      <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-1">
        <Icon size={12} className="text-slate-300" /> {label}
      </span>
      <p className={`text-sm font-black ${highlight ? 'text-blue-600' : 'text-slate-700'}`}>
        {value || "N/A"}
      </p>
    </div>
  );

  return (
    <main className="min-h-screen bg-zinc-50 p-6 flex flex-col items-center select-none cursor-default">
      <div className="w-full max-w-lg">
        
        {/* Enlace de regreso */}
        <Link href="/" className="flex items-center gap-2 text-slate-400 mb-8 font-black text-[10px] uppercase tracking-widest hover:text-blue-600 transition-colors">
          <ArrowLeft size={14} /> Volver al Inicio
        </Link>

        {/* CONTENEDOR TIPO FICHA */}
        <div className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200 border border-white overflow-hidden">
          
          {/* Encabezado Estilo Reporte */}
          <div className="bg-slate-900 p-10 text-white relative">
            <div className="relative z-10">
              <div className="flex items-center gap-2 text-blue-400 mb-2">
                <Shield size={16} />
                <span className="text-[10px] font-black uppercase tracking-[0.3em]">Certificado de Inventario</span>
              </div>
              <h1 className="text-3xl font-black italic uppercase tracking-tighter">#{data.numero_inventario}</h1>
              <p className="text-slate-400 text-xs font-bold mt-1 uppercase">{data.marca_modelo}</p>
            </div>
            <Monitor size={120} className="absolute right-[-20px] bottom-[-20px] text-white/5 -rotate-12" />
          </div>

          <div className="p-10 space-y-8">
            
            {/* Sección: Responsables */}
            <section>
              <h3 className="text-[11px] font-black text-blue-600 uppercase tracking-widest mb-4 border-b pb-2">Asignación</h3>
              <div className="grid grid-cols-2 gap-6">
                <InfoRow icon={User} label="Usuario Actual" value={data.responsable_inventario} />
                <InfoRow icon={Shield} label="Jefe de Área" value={data.responsable_area} />
              </div>
            </section>

            {/* Sección: Especificaciones Técnicas */}
            <section className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
              <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-4">Especificaciones Hardware</h3>
              <div className="space-y-4">
                <div className="grid grid-cols-3 gap-4">
                  <InfoRow icon={Cpu} label="CPU" value={data.procesador} />
                  <InfoRow icon={Activity} label="RAM" value={data.memoria_ram} />
                  <InfoRow icon={HardDrive} label="Disco" value={data.almacenamiento} />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <InfoRow icon={Monitor} label="Monitor" value={data.monitor} />
                  <InfoRow icon={Keyboard} label="Periféricos" value={data.mouse_teclado} />
                </div>
              </div>
            </section>

            {/* Sección: Estado y Notas */}
            <section className="space-y-6">
              <div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2 mb-2">
                  <MessageSquare size={12} /> Notas del Sistema
                </span>
                <div className="p-5 bg-yellow-50/50 rounded-2xl border border-yellow-100 text-xs text-slate-600 font-medium italic leading-relaxed">
                  {data.observacion || "Sin observaciones adicionales registradas."}
                </div>
              </div>

              {/* Banner de Mantenimiento Estático */}
              <div className={`flex items-center justify-between p-5 rounded-[2rem] border ${
                data.requiere_mantenimiento 
                ? 'bg-red-50 border-red-100 text-red-700' 
                : 'bg-emerald-50 border-emerald-100 text-emerald-700'
              }`}>
                <div className="flex items-center gap-3">
                  <AlertCircle size={20} className={data.requiere_mantenimiento ? "animate-pulse" : ""} />
                  <span className="text-xs font-black uppercase tracking-widest">
                    {data.requiere_mantenimiento ? "Atención Técnica Requerida" : "Estado: Operativo"}
                  </span>
                </div>
                <div className={`h-3 w-3 rounded-full ${data.requiere_mantenimiento ? 'bg-red-500' : 'bg-emerald-500'}`} />
              </div>
            </section>
          </div>

          {/* Footer del Documento */}
          <footer className="bg-slate-50 p-6 border-t border-slate-100 flex flex-col items-center gap-2">
            <div className="flex items-center gap-4 opacity-50">
               <div className="flex items-center gap-1 text-[9px] font-bold uppercase tracking-tighter">
                 <Calendar size={12} /> Revisión: {new Date(data.ultima_revision).toLocaleDateString()}
               </div>
               <div className="flex items-center gap-1 text-[9px] font-bold uppercase tracking-tighter">
                 <MapPin size={12} /> Juzgado Municipal
               </div>
            </div>
          </footer>
        </div>

        <p className="text-center mt-8 text-[9px] text-slate-300 font-bold uppercase tracking-[0.5em]">
          Documento Informativo No Editable
        </p>
      </div>
    </main>
  );
}